webpackJsonp([0xf927f8900006],{814:function(e,o){e.exports={data:{page:{id:"/Users/munniche/Documents/js-web-hack/1/shootmenow/content/pages/1--about/index.md absPath of file >>> MarkdownRemark",html:'<h3>Started in tech in 1993, been all down hill from then hahaha.</h3>\n<p>In all seriousness, I really love what I do and enjoy the constant challenge working in the tech industry provides.  This blog is another iteration of my blogging life, with a focus on ‘no zero days’ which is a manifestation of an idea heard on a podcast:</p>\n<ul>\n<li>never let a day go by without working on your goals and knowledge, no matter how small the effort is.</li>\n</ul>\n<p>aka never give up, yolo, etc etc.  Here goes!</p>\n<p>This site is based on a demo site of the <a href="https://github.com/greglobinski/gatsby-starter-personal-blog">PersonalBlog</a> GatsbyJS starter.</p>',frontmatter:{title:"About"}},footnote:{id:"/Users/munniche/Documents/js-web-hack/1/shootmenow/content/parts/footnote.md absPath of file >>> MarkdownRemark",html:""},site:{siteMetadata:{facebook:{appId:""}}}},pathContext:{slug:"/about/"}}}});
